const geminiResponse = $json;
const itemIndex = $itemIndex;

// Получаем оригинальные данные из Merge data
const mergeDataItems = $('Merge Data').all();
const inputItem = mergeDataItems[itemIndex]?.json || {};
const imageBinary = mergeDataItems[itemIndex]?.binary || null;

// Дефолтный результат
let qaResult = { 
  approved: true, 
  quality_score: 7, 
  rejection_reasons: [], 
  recommendation: 'approve' 
};

// Парсим ответ Gemini
try {
  const content = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  qaResult = JSON.parse(cleanJson);
} catch (e) {
  qaResult = { 
    approved: true, 
    quality_score: 6, 
    rejection_reasons: ['parse_error'], 
    recommendation: 'approve' 
  };
}

// Проверка на блокировку по safety
if (geminiResponse.candidates?.[0]?.finishReason === 'SAFETY') {
  qaResult = { 
    approved: false, 
    quality_score: 0, 
    rejection_reasons: ['safety_blocked'], 
    recommendation: 'reject' 
  };
}

// Формируем результат
const result = {
  json: {
    id: inputItem.id || '',
    section: inputItem.section || '',
    raw_title: inputItem.raw_title || '',
    page_url: inputItem.page_url || '',
    image_url: inputItem.image_url || '',
    raw_description: inputItem.raw_description || '',
    qa_approved: qaResult.approved !== false,
    qa_score: qaResult.quality_score || 5,
    qa_reasons: qaResult.rejection_reasons || [],
    qa_recommendation: qaResult.recommendation || 'approve'
  }
};

if (imageBinary) {
  result.binary = imageBinary;
}

return {
  json: {
    id: inputItem.id || '',
    section: inputItem.section || '',
    raw_title: inputItem.raw_title || '',
    page_url: inputItem.page_url || '',
    image_url: inputItem.image_url || '',
    raw_description: inputItem.raw_description || '',
    needs_file: inputItem.needs_file || false,
    download_url: inputItem.download_url || null,
    file_formats: inputItem.file_formats || [],
    qa_approved: qaResult.approved !== false,
    qa_score: qaResult.quality_score || 5,
    qa_reasons: qaResult.rejection_reasons || [],
    qa_recommendation: qaResult.recommendation || 'approve'
  },
  binary: imageBinary || undefined
};

const inputItem = $json;
const fileBinary = $binary?.data;

const timestamp = Date.now();
const safeTitle = (inputItem.raw_title || 'item').toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);

const imageFileName = `${inputItem.section}_${safeTitle}_${timestamp}.png`;
const modFileName = `${inputItem.section}_${safeTitle}_${timestamp}${inputItem.file_extension || '.mcaddon'}`;

return [{
  json: {
    ...inputItem,
    image_filename: imageFileName,
    mod_filename: modFileName,
    has_mod_file: true
  },
  binary: {
    mod_file: fileBinary
  }
}];

const inputItem = $json;
const imageBinary = $binary?.data;

const timestamp = Date.now();
const safeTitle = (inputItem.raw_title || 'item').toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);

const imageFileName = `${inputItem.section}_${safeTitle}_${timestamp}.png`;

return [{
  json: {
    ...inputItem,
    image_filename: imageFileName,
    mod_filename: null,
    has_mod_file: false
  },
  binary: {
    image: imageBinary
  }
}];

// Финализация элемента
const inputItem = $('Merge All Items').first().json;
const inputBinary = $('Merge All Items').first().binary;
const aiResponse = $json.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  const cleanJson = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  parsed = {
    title: (inputItem.raw_title || 'Minecraft Mod').substring(0, 30),
    description: `This ${inputItem.section} adds new features to Minecraft.`
  };
}

let title = parsed.title || inputItem.raw_title || 'Minecraft Mod';
title = title.replace(/[^a-zA-Z0-9\s-]/g, '').trim();
if (title.length < 4) title = title + ' Mod';
if (title.length > 30) title = title.substring(0, 27) + '...';

let description = parsed.description || '';
if (description.length < 50) {
  description = `${description} Enhances your Minecraft experience with new features and content.`;
}
if (description.length > 3000) {
  description = description.substring(0, 2997) + '...';
}

return [{
  json: {
    id: inputItem.id,
    section: inputItem.section,
    category: inputItem.category || 'general',
    image: inputItem.image_filename,
    file: inputItem.mod_filename || '',
    title: title,
    description: description,
    source_url: inputItem.page_url,
    qa_score: inputItem.qa_score
  },
  binary: inputBinary
}];

