    qa_score: item.qa_score,
    _chat_id: item._chat_id
  },
  binary: newBinary
};

const response = $json;
const configData = $('Config3').first().json;
const chatId = configData.chat_id;
const config = configData.config;
const briaToken = config.bria_api_token;

const allCosmetics = response.data || [];
console.log(`Total cosmetics from API: ${allCosmetics.length}`);

// Типы для маппинга
const TYPE_TO_SECTION = {
  'outfit': 'skins',
  'emote': 'emotes',
  'pickaxe': 'items',
  'glider': 'items',
  'backpack': 'items',
  'contrail': 'items',
  'wrap': 'items'
};

// Weapon типы
const WEAPON_TYPES = ['pickaxe'];

function normalizeRarity(r) {
  const val = (r?.value || 'other').toLowerCase();
  if (['common', 'uncommon', 'rare', 'epic', 'legendary'].includes(val)) return val;
  if (val.includes('legend')) return 'legendary';
  if (val.includes('epic')) return 'epic';
  if (val.includes('rare')) return 'rare';
  return 'other';
}

// Структуры для сбора
const sections = {
  skins: { items: [], byRarity: {} },
  emotes: { items: [], byRarity: {} },
  items: { items: [], byRarity: {}, weapons: [] }
};

const RARITIES = ['common', 'uncommon', 'rare', 'epic', 'legendary', 'other'];
for (const r of RARITIES) {
  sections.skins.byRarity[r] = [];
  sections.emotes.byRarity[r] = [];
  sections.items.byRarity[r] = [];
}

// Обработка всех cosmetics
for (const item of allCosmetics) {
  const type = item.type?.value || 'unknown';
  const section = TYPE_TO_SECTION[type];
  if (!section) continue;

  const imageUrl = item.images?.icon || item.images?.featured || item.images?.smallIcon;
  if (!imageUrl) continue;

  const rarity = normalizeRarity(item.rarity);
  const processed = {
    id: item.id,
    name: item.name || 'Unknown',
    description: item.description || '',
    rarity: rarity,
    type: type,
    section: section,
    image_url: imageUrl,
    set: item.set?.value || ''
  };

  sections[section].items.push(processed);
  sections[section].byRarity[rarity].push(processed);

  // Отдельно собираем weapons
  if (WEAPON_TYPES.includes(type)) {
    sections.items.weapons.push(processed);
  }
}

console.log(`Skins: ${sections.skins.items.length}`);
console.log(`Emotes: ${sections.emotes.items.length}`);
console.log(`Items: ${sections.items.items.length}`);
console.log(`Weapons: ${sections.items.weapons.length}`);

// Функция выбора с учётом rarity
function selectItems(sectionData, minTotal, minPerRarity) {
  const selected = [];
  const usedIds = new Set();

  for (const r of RARITIES) {
    const pool = sectionData.byRarity[r] || [];
    let count = 0;
    for (const item of pool) {
      if (count >= minPerRarity) break;
      if (usedIds.has(item.id)) continue;
      selected.push(item);
      usedIds.add(item.id);
      count++;
    }
  }

  if (selected.length < minTotal) {
    for (const item of sectionData.items) {
      if (selected.length >= minTotal) break;
      if (usedIds.has(item.id)) continue;
      selected.push(item);
      usedIds.add(item.id);
    }
  }

  return selected;
}

// Выбираем основные секции
const finalSkins = selectItems(sections.skins, 50, 10);
const finalEmotes = selectItems(sections.emotes, 50, 10);

// Items с обязательным weapon
let finalItems = selectItems(sections.items, 50, 10);
const hasWeapon = finalItems.some(i => WEAPON_TYPES.includes(i.type));
if (!hasWeapon && sections.items.weapons.length > 0) {
  // Добавляем weapon если нет
  const weapon = sections.items.weapons[0];
  if (!finalItems.find(i => i.id === weapon.id)) {
    finalItems.push(weapon);
  }
}

// === BUNDLES (50 шт × 4 элемента) ===
const bundles = [];
const usedForBundles = { skins: new Set(), emotes: new Set(), items: new Set() };

for (let i = 0; i < 50; i++) {
  // Выбираем по 1 skin, 1 emote, 2 items (один weapon)
  const bundleSkin = sections.skins.items.find(s => !usedForBundles.skins.has(s.id));
  const bundleEmote = sections.emotes.items.find(e => !usedForBundles.emotes.has(e.id));
  const bundleWeapon = sections.items.weapons.find(w => !usedForBundles.items.has(w.id));
  const bundleItem = sections.items.items.find(it => 
    !usedForBundles.items.has(it.id) && 
    !WEAPON_TYPES.includes(it.type) &&
    it.id !== bundleWeapon?.id
  );

  if (!bundleSkin || !bundleEmote || !bundleWeapon || !bundleItem) {
    console.log(`Bundle ${i}: not enough items`);
    continue;
  }

  usedForBundles.skins.add(bundleSkin.id);
  usedForBundles.emotes.add(bundleEmote.id);
  usedForBundles.items.add(bundleWeapon.id);
  usedForBundles.items.add(bundleItem.id);

  bundles.push({
    id: `bundle_${i}`,
    name: `${bundleSkin.name} Bundle`,
    rarity: bundleSkin.rarity,
    section: 'bundles',
    elements: [
      { type: 'skin', id: bundleSkin.id, name: bundleSkin.name, image_url: bundleSkin.image_url },
      { type: 'emote', id: bundleEmote.id, name: bundleEmote.name, image_url: bundleEmote.image_url },
      { type: 'weapon', id: bundleWeapon.id, name: bundleWeapon.name, image_url: bundleWeapon.image_url },
      { type: 'item', id: bundleItem.id, name: bundleItem.name, image_url: bundleItem.image_url }
    ],
    image_url: bundleSkin.image_url // Используем скин как обложку
  });
}

console.log(`Bundles created: ${bundles.length}`);

// === XP MAPS (50 шт + коды) ===
function generateCode() {
  const block = () => String(Math.floor(Math.random() * 10000)).padStart(4, '0');
  let code;
  do {
    code = `${block()}-${block()}-${block()}`;
  } while (
    code === '0000-0000-0000' ||
    code === '1111-1111-1111' ||
    code === '1234-1234-1234' ||
    code.split('-').every((b, i, arr) => b === arr[0])
  );
  return code;
}

const xpMaps = [];
const usedCodes = new Set();

const mapThemes = [
  'Deathrun', 'Parkour', 'Escape Room', 'Tycoon', 'Box Fight',
  'Zone Wars', 'Hide and Seek', 'Gun Game', 'Prop Hunt', 'Racing'
];

for (let i = 0; i < 50; i++) {
  let code;
  do {
    code = generateCode();
  } while (usedCodes.has(code));
  usedCodes.add(code);

  const theme = mapThemes[i % mapThemes.length];

  xpMaps.push({
    id: `xp_map_${i}`,
    name: `${theme} Map ${i + 1}`,
    description: `Fast-paced ${theme.toLowerCase()} course. Complete runs to earn XP and unlock rewards.`,
    code: code,
    tags: [theme.toLowerCase(), 'xp', 'creative'],
    section: 'xp_maps',
    needs_generation: true // Картинку будем генерировать
  });
}

console.log(`XP Maps created: ${xpMaps.length}`);

// === Собираем все items для обработки ===
const allSelected = [];
let idx = 0;

// Skins
for (const item of finalSkins) {
  allSelected.push({
    json: {
      ...item,
      _idx: idx++,
      _chat_id: chatId,
      _bria_token: briaToken,
      image_filename: `skins_${item.id}.png`,
      needs_generation: false
    }
  });
}

// Emotes
for (const item of finalEmotes) {
  allSelected.push({
    json: {
      ...item,
      _idx: idx++,
      _chat_id: chatId,
      _bria_token: briaToken,
      image_filename: `emotes_${item.id}.png`,
      needs_generation: false
    }
  });
}

// Items (с weapon)
for (const item of finalItems) {
  allSelected.push({
    json: {
      ...item,
      _idx: idx++,
      _chat_id: chatId,
      _bria_token: briaToken,
      image_filename: `items_${item.id}.png`,
      is_weapon: WEAPON_TYPES.includes(item.type),
      needs_generation: false
    }
  });
}

// Bundles
for (const bundle of bundles) {
  allSelected.push({
    json: {
      ...bundle,
      _idx: idx++,
      _chat_id: chatId,
      _bria_token: briaToken,
      image_filename: `bundles_${bundle.id}.png`,
      needs_generation: false
    }
  });
}

// XP Maps (needs generation)
for (const map of xpMaps) {
  allSelected.push({
    json: {
      ...map,
      _idx: idx++,
      _chat_id: chatId,
      _bria_token: briaToken,
      image_filename: `xp_maps_${map.id}.png`
    }
  });
}

console.log(`Total items to process: ${allSelected.length}`);

return allSelected;

