parameters.jsCode:
const genItems = $('Needs Generation?').all().filter(i => i.json.needs_generation);
const idx = $itemIndex;
const meta = genItems[idx]?.json || {};

const result = $input.item.json;
let imageB64 = '';

// Извлекаем base64 из ответа Gemini
const parts = result.candidates?.[0]?.content?.parts || [];
for (const part of parts) {
  if (part.inlineData?.data) {
    imageB64 = part.inlineData.data;
    break;
  }
}

if (!imageB64) {
  return { json: { ...meta, _skip: true, _gen_failed: true } };
}

return {
  json: { ...meta, _generated: true },
  binary: {
    [meta.image_filename]: {
      data: imageB64,
      mimeType: 'image/png',
      fileName: meta.image_filename
    }
  }
};

const apiItems = $('Needs Generation?').all().filter(i => !i.json.needs_generation);
const idx = $itemIndex;
const meta = apiItems[idx]?.json || {};

const briaResult = $input.item.json;
let resultUrl = briaResult.result?.image_url || briaResult.image_url || meta.image_url;

return {
  json: {
    ...meta,
    processed_url: resultUrl,
    bria_success: !!briaResult.result?.image_url
  }
};

parameters.jsonBody:
={
  "contents": [{
    "parts": [
      { "inline_data": { "mime_type": "image/png", "data": "{{ $json.data }}" } },
      { "text": "OCR check: Does this image contain any watermarks, logos, text overlays, UI elements, or signatures? Return JSON only: {\"has_watermark\": true/false, \"has_text\": true/false, \"text_found\": \"text if any\", \"approved\": true/false}. approved=false if watermark/logo/UI found." }
    ]
  }],
  "generationConfig": { "responseMimeType": "application/json", "temperature": 0 }
}

parameters.jsCode:
const filterItems = $('Has Image?1').all().filter(i => !i.json._skip);
const idx = $itemIndex;
const meta = filterItems[idx]?.json || {};
const binary = filterItems[idx]?.binary;

const ocrResult = $input.item.json;
let approved = true;
let hasWatermark = false;
let textFound = '';

try {
  const txt = ocrResult.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const parsed = JSON.parse(txt.replace(/```json\n?/g,'').replace(/```/g,'').trim());
  approved = parsed.approved !== false;
  hasWatermark = parsed.has_watermark === true;
  textFound = parsed.text_found || '';
} catch(e) {
  approved = true; // Если OCR не сработал - пропускаем
}

return {
  json: {
    ...meta,
    ocr_approved: approved,
    ocr_has_watermark: hasWatermark,
    ocr_text_found: textFound
  },
  binary: binary
};

const input = $json;
const chatId = input.message?.chat?.id || input.chat_id || 0;

const config = {
  requirements: {
    skins: { min: 50, minPerRarity: 10 },
    emotes: { min: 50, minPerRarity: 10 },
    items: { min: 50, minPerRarity: 10, weaponRequired: true },
    bundles: { min: 50, elementsPerBundle: 4 },
    xp_maps: { min: 50 }
  },
  rarities: ['common', 'uncommon', 'rare', 'epic', 'legendary', 'other'],
  imageSize: { width: 480, height: 650 },
  bria_api_token: '130a9262fe6349b9bc9fd2dfbd2fd2d8'
};

return [{ json: { chat_id: chatId, config: config } }];

const briaItems = $('Parse Bria').all();
const idx = $itemIndex;
const meta = briaItems[idx]?.json || {};

const current = $input.item;
const hasBinary = current.binary && Object.keys(current.binary).length > 0;

if (!hasBinary) {
  return { json: { ...meta, _skip: true } };
}

return {
  json: { ...meta },
  binary: current.binary
};

const ocrItems = $('OCR Approved?').all();
const idx = $itemIndex;
const meta = ocrItems[idx]?.json || {};
const binary = $input.item.binary;

const newBinary = {};
if (binary) {
  const key = Object.keys(binary)[0];
  if (key && binary[key]) {
    newBinary[meta.image_filename] = {
      ...binary[key],
      fileName: meta.image_filename,
      mimeType: 'image/png'
    };
  }
}

return {
  json: {
    id: meta.id,
    name: meta.name,
    description: meta.description || '',
    rarity: meta.rarity || 'other',
    type: meta.type || '',
    section: meta.section,
    image_filename: meta.image_filename,
    code: meta.code || '',
    tags: meta.tags || [],
    elements: meta.elements || [],
    is_weapon: meta.is_weapon || false,
    bria_success: meta.bria_success || false,
    _generated: meta._generated || false,
    _chat_id: meta._chat_id
  },
  binary: newBinary
};

const data = $json;
const items = data.final_items || [];
let chatId = 0;

const stats = { skins: 0, emotes: 0, items: 0, bundles: 0, xp_maps: 0, weapons: 0, generated: 0, bria: 0 };

for (const item of items) {
  if (item._chat_id) chatId = item._chat_id;
  stats[item.section] = (stats[item.section] || 0) + 1;
  if (item.is_weapon) stats.weapons++;
  if (item._generated) stats.generated++;
  if (item.bria_success) stats.bria++;
}

console.log('Final stats:', stats);

// CSV files
const csvSkins = ['id,name,rarity,image,description'];
const csvEmotes = ['id,name,rarity,image,description'];
const csvItems = ['id,name,rarity,type,is_weapon,image,description'];
const csvBundles = ['id,name,rarity,image,skin_id,emote_id,weapon_id,item_id'];
const csvXpMaps = ['id,name,code,tags,image,description'];

for (const item of items) {
  const name = (item.name || '').replace(/"/g, '').replace(/,/g, ' ');
  const desc = (item.description || '').replace(/"/g, '').replace(/,/g, ' ').substring(0, 200);

  if (item.section === 'skins') {
    csvSkins.push(`${item.id},"${name}",${item.rarity},${item.image_filename},"${desc}"`);
  } else if (item.section === 'emotes') {
    csvEmotes.push(`${item.id},"${name}",${item.rarity},${item.image_filename},"${desc}"`);
  } else if (item.section === 'items') {
    csvItems.push(`${item.id},"${name}",${item.rarity},${item.type},${item.is_weapon},${item.image_filename},"${desc}"`);
  } else if (item.section === 'bundles') {
    const els = item.elements || [];
    const skinId = els.find(e => e.type === 'skin')?.id || '';
    const emoteId = els.find(e => e.type === 'emote')?.id || '';
    const weaponId = els.find(e => e.type === 'weapon')?.id || '';
    const itemId = els.find(e => e.type === 'item')?.id || '';
    csvBundles.push(`${item.id},"${name}",${item.rarity},${item.image_filename},${skinId},${emoteId},${weaponId},${itemId}`);
  } else if (item.section === 'xp_maps') {
    const tags = (item.tags || []).join(';');
    csvXpMaps.push(`${item.id},"${name}",${item.code},"${tags}",${item.image_filename},"${desc}"`);
  }
}

const finalizeItems = $('Finalize1').all();
const binaryKeys = [];
const binaryData = {};

binaryData['skins.csv'] = { data: Buffer.from(csvSkins.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'skins.csv' };
binaryData['emotes.csv'] = { data: Buffer.from(csvEmotes.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'emotes.csv' };
binaryData['items.csv'] = { data: Buffer.from(csvItems.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'items.csv' };
binaryData['bundles.csv'] = { data: Buffer.from(csvBundles.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'bundles.csv' };
binaryData['xp_maps.csv'] = { data: Buffer.from(csvXpMaps.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'xp_maps.csv' };
binaryKeys.push('skins.csv', 'emotes.csv', 'items.csv', 'bundles.csv', 'xp_maps.csv');

for (const item of finalizeItems) {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      binaryData[key] = item.binary[key];
      binaryKeys.push(key);
    }
  }
}

return {
  json: {
    total_items: items.length,
    stats: stats,
    chat_id: chatId,
    binary_keys: binaryKeys.join(',')
  },
  binary: binaryData
};

